Here's an **AgentFacts** schema for `myapp.io` following the NANDA protocol. This file would be served at `https://myapp.io/.well-known/agent.json`:

```json
{
  "agentfacts_version": "1.0.0",
  "schema": "https://nanda-registry.com/schemas/agentfacts/v1.0.0",

  "identity": {
    "id": "did:web:myapp.io",
    "name": "MyApp AI Agent",
    "description": "A SaaS AI agent supporting text and image capabilities with secure OAuth2 access.",
    "version": "1.0.0",
    "url": "https://myapp.io",
    "logo": "https://myapp.io/assets/logo.png",
    "terms_of_service": "https://myapp.io/terms",
    "privacy_policy": "https://myapp.io/privacy"
  },

  "provider": {
    "name": "MyApp Inc.",
    "url": "https://myapp.io",
    "contact": "support@myapp.io"
  },

  "capabilities": {
    "modalities": ["text", "image"],
    "input": {
      "text": {
        "formats": ["plain", "markdown", "html"],
        "max_tokens": 32768,
        "languages": ["en"]
      },
      "image": {
        "formats": ["jpeg", "png", "webp", "gif"],
        "max_size_mb": 20,
        "max_resolution": "4096x4096"
      }
    },
    "output": {
      "text": {
        "formats": ["plain", "markdown"],
        "max_tokens": 8192,
        "streaming": true
      },
      "image": {
        "formats": ["jpeg", "png", "webp"],
        "generation": true,
        "editing": true
      }
    },
    "features": [
      "streaming",
      "multi-turn",
      "function-calling",
      "vision"
    ]
  },

  "api": {
    "base_url": "https://api.myapp.io/v1",
    "protocol": "https",
    "endpoints": {
      "chat": {
        "path": "/chat/completions",
        "method": "POST",
        "description": "Send text or image messages and receive completions.",
        "openapi": "https://api.myapp.io/v1/openapi.json"
      },
      "images": {
        "path": "/images/generate",
        "method": "POST",
        "description": "Generate images from a text prompt."
      },
      "health": {
        "path": "/health",
        "method": "GET",
        "description": "Service health status."
      }
    }
  },

  "authentication": {
    "type": "oauth2",
    "oauth2": {
      "authorization_url": "https://auth.myapp.io/oauth/authorize",
      "token_url": "https://auth.myapp.io/oauth/token",
      "revocation_url": "https://auth.myapp.io/oauth/revoke",
      "jwks_uri": "https://auth.myapp.io/.well-known/jwks.json",
      "grant_types": ["authorization_code", "client_credentials"],
      "response_types": ["code"],
      "scopes": {
        "chat:read": "Read access to chat completions",
        "chat:write": "Create chat completions",
        "images:generate": "Generate images",
        "images:read": "Read generated images"
      },
      "pkce_required": true,
      "token_endpoint_auth_methods": ["client_secret_basic", "client_secret_post"]
    }
  },

  "compliance": {
    "data_residency": ["us-east-1", "eu-west-1"],
    "certifications": ["SOC2", "GDPR"],
    "content_policy": "https://myapp.io/content-policy"
  },

  "rate_limits": {
    "requests_per_minute": 60,
    "tokens_per_minute": 100000,
    "images_per_minute": 10,
    "documentation": "https://docs.myapp.io/rate-limits"
  },

  "discovery": {
    "nanda_registry": true,
    "tags": ["text-generation", "image-generation", "multimodal", "saas"],
    "categories": ["productivity", "ai-assistant"]
  }
}
```

---

**Key design decisions:**

| Field | Choice | Reason |
|---|---|---|
| `identity.id` | `did:web:` DID | NANDA-recommended decentralized identifier |
| `authentication.type` | `oauth2` | As specified; includes PKCE for security |
| `grant_types` | `authorization_code` + `client_credentials` | Human users + machine-to-machine both covered |
| `pkce_required` | `true` | Required for public clients per RFC 7636 |
| `capabilities.modalities` | `["text", "image"]` | Both input and output defined separately |
| `api.endpoints` | Structured map | Allows agents to discover endpoints programmatically |

**Deployment:** Serve this file with `Content-Type: application/json` and `Access-Control-Allow-Origin: *` at `/.well-known/agent.json`. Register the `did:web:myapp.io` DID by also publishing `https://myapp.io/.well-known/did.json`.
